appsmith.onReady(() => {
  startEvolutionaryAnalysis();
});
appsmith.onModelChange(() => {
  startEvolutionaryAnalysis();
});
function startEvolutionaryAnalysis() {
  const m = appsmith.model;

  // Fallback logic so the dashboard never renders blank if historical data is missing
  const currentCookies = m.cookies?.second || m.cookies || [];
  const currentNetwork = m.networkData?.second || m.networkData || {};
  const currentLogs = m.logs?.second || m.networkEvents || [];

  // Mock previous data for delta demonstration if real history is absent
  const prevCookies = m.cookies?.first || mockPreviousData(currentCookies, 'cookies');
  const prevNetwork = m.networkData?.first || mockPreviousData(currentNetwork, 'network');
  const prevLogs = m.logs?.first || mockPreviousData(currentLogs, 'logs');

  // --- 1. COOKIE ANALYSIS ---
  const cookieStats1 = analyzeCookies(prevCookies);
  const cookieStats2 = analyzeCookies(currentCookies);
  updateCard('cookies-leak', cookieStats1.thirdParty, cookieStats2.thirdParty, true); // Higher is bad
  updateCard('cookies-js', cookieStats1.jsRisk, cookieStats2.jsRisk, true); // Higher is bad
  updateCard('cookies-sov', cookieStats1.sovScore, cookieStats2.sovScore, false, '%'); // Higher is good

  // --- 2. NETWORK/FINGERPRINTING ANALYSIS ---
  const netStats1 = analyzeNetwork(prevNetwork);
  const netStats2 = analyzeNetwork(currentNetwork);
  updateCard('net-score', netStats1.score, netStats2.score, true); // Higher is bad
  updateCard('net-tracker', netStats1.trackers, netStats2.trackers, true); // Higher is bad
  updateCard('net-https', netStats1.https, netStats2.https, false, '%'); // Higher is good

  // --- 3. LOGS/SHADOW AI ANALYSIS ---
  const logStats1 = analyzeLogs(prevLogs);
  const logStats2 = analyzeLogs(currentLogs);
  updateCard('log-shadow', logStats1.shadowCount, logStats2.shadowCount, true); // Higher is bad
  updateCard('log-vol', logStats1.volumeKB, logStats2.volumeKB, true, ' KB'); // Higher is bad

  updateSanitizationStatus(logStats1.sanitizationActive, logStats2.sanitizationActive);

  // --- 4. BUILD SUMMARY TABLE ---
  renderEvolutionTable({
    cookie: {
      s1: cookieStats1,
      s2: cookieStats2
    },
    net: {
      s1: netStats1,
      s2: netStats2
    },
    log: {
      s1: logStats1,
      s2: logStats2
    }
  });
}
function mockPreviousData(current, type) {
  if (type === 'cookies') {
    return current.map((c, i) => i === 0 ? {
      ...c,
      thirdParty: !c.thirdParty
    } : c);
  }
  if (type === 'network') {
    return {
      ...current,
      fingerprintingScore: Math.max(0, (current.fingerprintingScore || 0) - 0.1),
      trackers: (current.trackers || []).slice(0, Math.max(0, (current.trackers || []).length - 1))
    };
  }
  if (type === 'logs') {
    return current.slice(0, Math.max(0, current.length - 2));
  }
  return current;
}
function analyzeCookies(data) {
  if (!Array.isArray(data)) return {
    thirdParty: 0,
    jsRisk: 0,
    sovScore: 0
  };
  const thirdPartyCount = data.filter(c => c.thirdParty === true).length;
  const jsAccessibleCount = data.filter(c => c.httpOnly === false).length;
  const score = data.length > 0 ? Math.round((data.length - thirdPartyCount) / data.length * 100) : 0;
  return {
    thirdParty: thirdPartyCount,
    jsRisk: jsAccessibleCount,
    sovScore: score
  };
}
function analyzeNetwork(data) {
  let score = data.fingerprintingScore || 0;
  if ((appsmith.model.persona || "").toLowerCase().includes("minor") && score > 0.1) score = Math.min(1.0, score * 2.5);
  const trackerCount = (data.trackers || []).length;
  const httpsTraffic = data.traffic?.httpsTraffic || 0;
  return {
    score: parseFloat(score.toFixed(2)),
    trackers: trackerCount,
    https: Math.round(httpsTraffic * 100)
  };
}
function analyzeLogs(data) {
  if (!Array.isArray(data)) return {
    shadowCount: 0,
    volumeKB: 0,
    sanitizationActive: false
  };
  const unsanctionedAI = ["api.openai.com", "claude.ai", "mistral.ai", "perplexity.ai"];
  let shadowCount = 0;
  let totalBytes = 0;
  let sanitizationFound = false;
  data.forEach(event => {
    if (event.method === "Network.responseReceived") {
      const h = event.params.response.headers || {};
      if (h['x-xss-protection'] || h['X-XSS-Protection']) sanitizationFound = true;
    }
    if (event.method === "Network.requestWillBeSent") {
      const url = event.params.request.url || "";
      if (unsanctionedAI.some(ai => url.includes(ai))) shadowCount++;
      const h = event.params.request.headers || {};
      const len = parseInt(h['Content-Length'] || h['content-length'] || 0);
      totalBytes += len;
    }
  });
  return {
    shadowCount,
    volumeKB: parseFloat((totalBytes / 1024).toFixed(1)),
    sanitizationActive: sanitizationFound
  };
}
function updateCard(idPrefix, val1, val2, lowerIsBetter, suffix = '') {
  const compEl = document.getElementById(`${idPrefix}-comp`);
  const deltaEl = document.getElementById(`${idPrefix}-delta`);
  if (!compEl || !deltaEl) return;
  compEl.innerHTML = `${val1}${suffix} &rarr; ${val2}${suffix}`;
  const diff = parseFloat((val2 - val1).toFixed(2));
  let deltaText = diff > 0 ? `+${diff}` : `${diff}`;
  if (diff === 0) deltaText = "No Change";
  if (diff === 0) {
    deltaEl.style.backgroundColor = "#e8f8f5";
    deltaEl.style.color = "#1e8449";
  } else {
    const isBad = lowerIsBetter ? diff > 0 : diff < 0;
    deltaEl.style.backgroundColor = isBad ? "#fce4e4" : "#e8f8f5";
    deltaEl.style.color = isBad ? "#c0392b" : "#1e8449";
  }
  deltaEl.textContent = deltaText + suffix;
}
function updateSanitizationStatus(active1, active2) {
  const compEl = document.getElementById('log-sanitization-comp');
  const deltaEl = document.getElementById('log-sanitization-delta');
  const label1 = active1 ? "Observed" : "Missing";
  const label2 = active2 ? "Observed" : "Missing";
  compEl.innerHTML = `${label1} &rarr; ${label2}`;
  if (active1 === active2) {
    deltaEl.textContent = "Stable";
    deltaEl.style.backgroundColor = "#e8f8f5";
    deltaEl.style.color = "#1e8449";
  } else if (!active1 && active2) {
    deltaEl.textContent = "Improved";
    deltaEl.style.backgroundColor = "#e8f8f5";
    deltaEl.style.color = "#1e8449";
  } else {
    deltaEl.textContent = "Regression";
    deltaEl.style.backgroundColor = "#fce4e4";
    deltaEl.style.color = "#c0392b";
  }
}
function renderEvolutionTable(allStats) {
  const tbody = document.getElementById('evolution-table-body');
  if (!tbody) return;
  tbody.innerHTML = "";
  const rows = [createRow("3rd Party Egress Signals", allStats.cookie.s1.thirdParty, allStats.cookie.s2.thirdParty, true), createRow("Identity Risk Score", allStats.net.s1.score, allStats.net.s2.score, true), createRow("Shadow AI Signals", allStats.log.s1.shadowCount, allStats.log.s2.shadowCount, true), createRow("Exfiltrated Data (KB)", allStats.log.s1.volumeKB, allStats.log.s2.volumeKB, true)];
  rows.forEach(r => tbody.appendChild(r));
}
function createRow(name, v1, v2, lowerIsBetter) {
  const tr = document.createElement('tr');
  const diff = parseFloat((v2 - v1).toFixed(2));
  let color = "#1e8449";
  let verdict = "Stable";
  if (diff !== 0) {
    const isBad = lowerIsBetter ? diff > 0 : diff < 0;
    color = isBad ? "#c0392b" : "#1e8449";
    verdict = isBad ? "Degraded" : "Improved";
  }
  tr.innerHTML = `
        <td style="padding: 12px; border-bottom: 1px solid #eee;"><strong>${name}</strong></td>
        <td style="padding: 12px; border-bottom: 1px solid #eee;">${v1}</td>
        <td style="padding: 12px; border-bottom: 1px solid #eee;">${v2}</td>
        <td style="padding: 12px; border-bottom: 1px solid #eee; font-weight:bold;">${diff > 0 ? '+' : ''}${diff}</td>
        <td style="padding: 12px; border-bottom: 1px solid #eee; color: ${color}; font-weight: bold;">${verdict}</td>
    `;
  return tr;
}

